  1	import * as React from 'react';
  2	import { getName, useCustomTranslation } from '@odf/shared';
  3	import {
  4	  Button,
  5	  Checkbox,
  6	  Divider,
  7	  ExpandableSection,
  8	  Flex,
  9	  FlexItem,
 10	  FormGroup,
 11	  FormHelperText,
 12	  HelperText,
 13	  HelperTextItem,
 14	  TextInput,
 15	} from '@patternfly/react-core';
 16	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 17	import { DRPolicyActionType, ManagedClusterInfoType } from '../utils/reducer';
 18	
 19	export type S3Details = {
 20	  clusterName: string;
 21	  bucketName: string;
 22	  endpoint: string;
 23	  accessKeyId: string;
 24	  secretKey: string;
 25	  region: string;
 26	  s3ProfileName: string;
 27	};
 28	
 29	type ClusterS3BucketDetailsFormProps = {
 30	  selectedClusters: ManagedClusterInfoType[];
 31	  cluster1Details: S3Details;
 32	  cluster2Details: S3Details;
 33	  useSameConnection: boolean;
 34	  dispatch: React.Dispatch<any>;
 35	  areDRClustersAlreadyCreated?: boolean;
 36	};
 37	
 38	export const ClusterS3BucketDetailsForm: React.FC<
 39	  ClusterS3BucketDetailsFormProps
 40	> = ({
 41	  selectedClusters,
 42	  cluster1Details,
 43	  cluster2Details,
 44	  useSameConnection,
 45	  areDRClustersAlreadyCreated,
 46	  dispatch,
 47	}) => {
 48	  const { t } = useCustomTranslation();
 49	  const [expanded1, setExpanded1] = React.useState(true);
 50	  const [expanded2, setExpanded2] = React.useState(true);
 51	  const [show1, setShow1] = React.useState(false);
 52	  const [show2, setShow2] = React.useState(false);
 53	
 54	  const [errors1, setErrors1] = React.useState<Partial<S3Details>>({});
 55	  const [errors2, setErrors2] = React.useState<Partial<S3Details>>({});
 56	
 57	  const name1 = getName(selectedClusters[0]) || 'cluster-1';
 58	  const name2 = getName(selectedClusters[1]) || 'cluster-2';
 59	
 60	  React.useEffect(() => {
 61	    if (useSameConnection) {
 62	      dispatch({
 63	        type: DRPolicyActionType.SET_CLUSTER2_S3_DETAILS,
 64	        payload: { ...cluster1Details, clusterName: name2 },
 65	      });
 66	      setErrors2({});
 67	    }
 68	  }, [useSameConnection, cluster1Details, dispatch, name2]);
 69	
 70	  const handleBlur = (cluster: 1 | 2) => {
 71	    const details = cluster === 1 ? cluster1Details : cluster2Details;
 72	    validate(cluster, details);
 73	  };
 74	
 75	  const validate = (cluster: 1 | 2, details: S3Details) => {
 76	    const errs: Partial<S3Details> = {};
 77	
 78	    if (!details.bucketName.trim()) {
 79	      errs.bucketName = t('This field is required');
 80	    } else if (
 81	      !/^[a-z0-9][a-z0-9.-]*[a-z0-9]$/.test(details.bucketName) ||
 82	      details.bucketName.length < 3 ||
 83	      details.bucketName.length > 63
 84	    ) {
 85	      errs.bucketName = t(
 86	        'Bucket name must be 3-63 characters, lowercase letters, numbers, dots, and hyphens'
 87	      );
 88	    }
 89	
 90	    if (!details.endpoint.trim()) {
 91	      errs.endpoint = t('This field is required');
 92	    } else if (!/^https?:\/\/.+/.test(details.endpoint)) {
 93	      errs.endpoint = t('Endpoint must be a valid URL (http:// or https://)');
 94	    }
 95	
 96	    if (!details.accessKeyId.trim()) {
 97	      errs.accessKeyId = t('This field is required');
 98	    }
 99	
100	    if (!details.secretKey.trim()) {
101	      errs.secretKey = t('This field is required');
102	    }
103	
104	    if (!details.region.trim()) {
105	      errs.region = t('This field is required');
106	    }
107	
108	    if (!details.s3ProfileName.trim()) {
109	      errs.s3ProfileName = t('This field is required');
110	    } else if (!/^[a-zA-Z0-9_-]+$/.test(details.s3ProfileName)) {
111	      errs.s3ProfileName = t(
112	        'Profile name can only contain letters, numbers, hyphens, and underscores'
113	      );
114	    }
115	
116	    cluster === 1 ? setErrors1(errs) : setErrors2(errs);
117	    return Object.keys(errs).length === 0;
118	  };
119	
120	  const update = (cluster: 1 | 2, field: keyof S3Details, val: string) => {
121	    const base = cluster === 1 ? cluster1Details : cluster2Details;
122	    const clusterName = cluster === 1 ? name1 : name2;
123	
124	    const payload: S3Details = {
125	      ...base,
126	      [field]: val,
127	      clusterName,
128	    };
129	
130	    dispatch({
131	      type:
132	        cluster === 1
133	          ? DRPolicyActionType.SET_CLUSTER1_S3_DETAILS
134	          : DRPolicyActionType.SET_CLUSTER2_S3_DETAILS,
135	      payload,
136	    });
137	
138	    validate(cluster, payload);
139	  };
140	
141	  const onToggleSame = (_e, checked: boolean) => {
142	    dispatch({
143	      type: DRPolicyActionType.SET_USE_SAME_S3_CONNECTION,
144	      payload: checked,
145	    });
146	  };
147	
148	  const fields: Array<{ key: keyof S3Details; label: string }> = [
149	    { key: 'bucketName', label: t('Bucket name') },
150	    { key: 'endpoint', label: t('Endpoint') },
151	    { key: 'accessKeyId', label: t('Access key ID') },
152	    { key: 'secretKey', label: t('Secret key') },
153	    { key: 'region', label: t('Region') },
154	    { key: 's3ProfileName', label: t('S3 profile name') },
155	  ];
156	
157	  const inputPadding = 'pf-v6-u-p-sm pf-v6-u-w-75';
158	
159	  return (
160	    <div className="pf-v6-u-p-md">
161	      <ExpandableSection
162	        toggleText={
163	          areDRClustersAlreadyCreated
164	            ? t(`Previously used S3 bucket for {{name}}`, { name: name1 })
165	            : t(`S3 bucket for {{name}}`, { name: name1 })
166	        }
167	        isExpanded={expanded1}
168	        onToggle={(_, exp) => setExpanded1(exp)}
169	        isIndented
170	      >
171	        {fields.map(({ key, label }) => (
172	          <FormGroup
173	            key={key}
174	            fieldId={`c1-${key}`}
175	            label={label}
176	            isRequired
177	            className={inputPadding}
178	          >
179	            {key === 'secretKey' ? (
180	              <Flex alignItems={{ default: 'alignItemsCenter' }}>
181	                <FlexItem flex={{ default: 'flex_1' }}>
182	                  <TextInput
183	                    type={show1 ? 'text' : 'password'}
184	                    id={`c1-${key}`}
185	                    value={cluster1Details[key]}
186	                    placeholder={t('Enter the {{label}}', {
187	                      label: label.toLowerCase(),
188	                    })}
189	                    onChange={(_, v) => update(1, key, v)}
190	                    validated={errors1[key] ? 'error' : 'default'}
191	                    onBlur={() => handleBlur(1)}
192	                  />
193	                </FlexItem>
194	                <FlexItem>
195	                  <Button
196	                    variant="plain"
197	                    onClick={() => setShow1((s) => !s)}
198	                    aria-label={t('Toggle secret visibility')}
199	                  >
200	                    {show1 ? <EyeSlashIcon /> : <EyeIcon />}
201	                  </Button>
202	                </FlexItem>
203	              </Flex>
204	            ) : (
205	              <TextInput
206	                id={`c1-${key}`}
207	                value={cluster1Details[key]}
208	                placeholder={t('Enter the {{label}}', {
209	                  label: label.toLowerCase(),
210	                })}
211	                onChange={(_, v) => update(1, key, v)}
212	                validated={errors1[key] ? 'error' : 'default'}
213	                onBlur={() => handleBlur(1)}
214	              />
215	            )}
216	            {errors1[key] && (
217	              <HelperText>
218	                <HelperTextItem variant="error">{errors1[key]}</HelperTextItem>
219	              </HelperText>
220	            )}
221	          </FormGroup>
222	        ))}
223	      </ExpandableSection>
224	      <Divider className="pf-v6-u-p-md" />
225	      <ExpandableSection
226	        toggleText={
227	          areDRClustersAlreadyCreated
228	            ? t(`Previously used S3 bucket for {{name}}`, { name: name2 })
229	            : t(`S3 bucket for {{name}}`, { name: name2 })
230	        }
231	        isExpanded={expanded2}
232	        onToggle={(_, exp) => setExpanded2(exp)}
233	        isIndented
234	      >
235	        <Checkbox
236	          id="use-same-conn"
237	          label={t('Use the same S3 connection details as the first cluster')}
238	          isChecked={useSameConnection}
239	          onChange={onToggleSame}
240	        />
241	        {fields.map(({ key, label }) => (
242	          <FormGroup
243	            key={key}
244	            fieldId={`c2-${key}`}
245	            label={label}
246	            isRequired
247	            className={inputPadding}
248	          >
249	            {key === 'secretKey' ? (
250	              <div style={{ display: 'flex', alignItems: 'center' }}>
251	                <TextInput
252	                  type={show2 ? 'text' : 'password'}
253	                  id={`c2-${key}`}
254	                  value={cluster2Details[key]}
255	                  placeholder={t('Enter the {{label}}', {
256	                    label: label.toLowerCase(),
257	                  })}
258	                  onChange={(_, v) => update(2, key, v)}
259	                  validated={errors2[key] ? 'error' : 'default'}
260	                  isDisabled={useSameConnection}
261	                  style={{ flex: 1 }}
262	                  onBlur={() => handleBlur(2)}
263	                />
264	                <Button
265	                  variant="plain"
266	                  onClick={() => setShow2((s) => !s)}
267	                  aria-label={t('Toggle secret visibility')}
268	                  isDisabled={useSameConnection}
269	                >
270	                  {show2 ? <EyeSlashIcon /> : <EyeIcon />}
271	                </Button>
272	              </div>
273	            ) : (
274	              <TextInput
275	                id={`c2-${key}`}
276	                value={cluster2Details[key]}
277	                placeholder={t('Enter the {{label}}', {
278	                  label: label.toLowerCase(),
279	                })}
280	                onChange={(_, v) => update(2, key, v)}
281	                validated={errors2[key] ? 'error' : 'default'}
282	                isDisabled={useSameConnection}
283	                onBlur={() => handleBlur(2)}
284	              />
285	            )}
286	            {errors2[key] && <FormHelperText>{errors2[key]}</FormHelperText>}
287	          </FormGroup>
288	        ))}
289	      </ExpandableSection>
290	    </div>
291	  );
292	};

